mapper.insert:
INSERT INTO CMS_ACCESS_LOG (
	year, month, day, time, worker_id,
	menu_id, access_type, access_log, site_id

	, access_ip

) VALUES (
	TO_CHAR(SYSDATE, 'YYYY'), TO_CHAR(SYSDATE, 'MM'), TO_CHAR(SYSDATE, 'DD'), TO_CHAR(SYSTIMESTAMP, 'HH24MISS.FF'),
	#{worker_id}, #{menu_id}, #{access_type}, #{access_log}, #{site_id}

	, #{access_ip}

)

mapper.select:
SELECT
	COUNT(*)
FROM
	CMS_ACCESS_LOG a, cms_homepage b
WHERE a.SITE_ID = b.HOMEPAGE_ID
AND a.site_id != 'CMS'

AND worker_id = #{worker_id}


AND access_type = #{access_type}


AND #{start_date} <= TO_DATE(year||month||day, 'YYYYMMDD')


AND TO_DATE(year||month||day, 'YYYYMMDD') <= #{end_date}


	AND site_id  = #{site_id}

ORDER BY year DESC, month DESC, day DESC, time DESC

${pagingTop}
SELECT
	a.YEAR, a.MONTH, a.DAY, a.TIME, a.WORKER_ID,
	a.MENU_ID, a.ACCESS_TYPE, a.ACCESS_LOG, a.ACCESS_IP, a.SITE_ID,
	b.HOMEPAGE_NAME, (select member_name from cms_member where a.worker_id = member_id) as member_name
FROM
	CMS_ACCESS_LOG a, CMS_HOMEPAGE b
WHERE a.SITE_ID = b.HOMEPAGE_ID
AND a.site_id != 'CMS'

AND worker_id = #{worker_id}


AND access_type = #{access_type}


AND #{start_date} <= TO_DATE(year||month||day, 'YYYYMMDD')


AND TO_DATE(year||month||day, 'YYYYMMDD') <= #{end_date}


	AND a.site_id  = #{site_id}

ORDER BY year DESC, month DESC, day DESC, time DESC
${pagingBottom}

SELECT a.YEAR, a.MONTH, a.DAY, a.TIME, a.WORKER_ID, a.MENU_ID, a.ACCESS_TYPE, a.ACCESS_LOG, a.ACCESS_IP, a.SITE_ID, b.HOMEPAGE_NAME, c.MEMBER_NAME FROM CMS_ACCESS_LOG a, CMS_HOMEPAGE b, CMS_MEMBER c WHERE a.SITE_ID = b.HOMEPAGE_ID AND a.site_id != 'CMS' AND a.worker_id = c.member_id
AND worker_id = #{worker_id}
AND access_type = #{access_type}
AND #{start_date} <= TO_DATE(year||month||day, 'YYYYMMDD')
AND TO_DATE(year||month||day, 'YYYYMMDD') <= #{end_date}
AND a.site_id = #{site_id}
ORDER BY year DESC, month DESC, day DESC, time DESC
